## Logging Requirements

### Per-Benchmark Logging
```rust
use criterion::{criterion_group, criterion_main, Criterion, BenchmarkId};
use tracing::info;

fn storage_benchmarks(c: &mut Criterion) {
    let mut group = c.benchmark_group("storage");

    // Log benchmark configuration
    info!("benchmark_group_start: name=storage");

    group.bench_function("create_issue_single", |b| {
        info!("benchmark_start: create_issue_single");
        let setup_start = std::time::Instant::now();

        // Setup
        let temp_dir = tempfile::tempdir().unwrap();
        let storage = SqliteStorage::open(temp_dir.path()).unwrap();

        info!("benchmark_setup: create_issue_single duration={:?}", setup_start.elapsed());

        b.iter(|| {
            let issue = Issue::new("Test issue".to_string());
            storage.create_issue(&issue).unwrap();
        });

        info!("benchmark_end: create_issue_single");
    });

    group.finish();
    info!("benchmark_group_end: name=storage");
}
```

### Scaling Benchmarks
```rust
fn list_scaling(c: &mut Criterion) {
    let mut group = c.benchmark_group("list_scaling");

    for size in [100, 500, 1000, 5000].iter() {
        info!("benchmark_scaling: list size={}", size);

        group.bench_with_input(BenchmarkId::new("list_issues", size), size, |b, &size| {
            // Setup with 'size' issues
            let (storage, _temp) = setup_with_issues(size);

            b.iter(|| {
                storage.list_issues(&ListFilters::default()).unwrap()
            });
        });
    }

    group.finish();
}
```

### HTML Report Generation
```rust
// At benchmark completion, log report location
info!("benchmark_report: generated at target/criterion/report/index.html");

// Custom summary
info!("benchmark_summary: {{");
info!("  create_issue_single: mean={:.2}us p95={:.2}us", mean_us, p95_us);
info!("  list_issues_100: mean={:.2}ms p95={:.2}ms", mean_ms, p95_ms);
info!("}}");
```

### CI Integration Logging
```rust
// Output machine-readable metrics for CI
println!("::set-output name=create_issue_p95::{:.2}", p95_us);
println!("::set-output name=list_1000_mean::{:.2}", mean_ms);

// Alert on regression
if current_p95 > baseline_p95 * 1.1 {
    warn!("REGRESSION: create_issue_single p95 increased by {:.1}%", 
          (current_p95 / baseline_p95 - 1.0) * 100.0);
}
```

## Usage
```bash
# Run all benchmarks
cargo bench

# Run specific group
cargo bench --bench benchmarks storage

# Compare against baseline
cargo bench -- --save-baseline main
cargo bench -- --baseline main

# Results location
open target/criterion/report/index.html
```

